import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const m=JSON.parse('{"title":"PDF Import","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pdf-import.md","filePath":"guide/pdf-import.md","lastUpdated":1772287587000}'),i={name:"guide/pdf-import.md"};function s(n,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="pdf-import" tabindex="-1">PDF Import <a class="header-anchor" href="#pdf-import" aria-label="Permalink to &quot;PDF Import&quot;">​</a></h1><p>getbased can read any lab report PDF — any format, any lab, any language, any country. Drop the file on the dashboard and the AI extracts all your results automatically.</p><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h2><p>You need an AI provider configured in <strong>Settings → AI Provider</strong>. If you haven&#39;t done this yet, see <a href="./ai-providers.html">AI Providers</a> first.</p><h2 id="how-to-import" tabindex="-1">How to Import <a class="header-anchor" href="#how-to-import" aria-label="Permalink to &quot;How to Import&quot;">​</a></h2><ol><li>Open the getbased dashboard</li><li>Drag your lab PDF and drop it onto the <strong>drop zone</strong> at the top of the page</li><li>Wait while the AI reads and analyzes the report (typically 5–20 seconds)</li><li>Review the <strong>import preview</strong></li><li>Click <strong>Confirm</strong> to save the results</li></ol><p>That&#39;s it. Your data appears in charts immediately after confirming.</p><h2 id="pre-flight-checks" tabindex="-1">Pre-Flight Checks <a class="header-anchor" href="#pre-flight-checks" aria-label="Permalink to &quot;Pre-Flight Checks&quot;">​</a></h2><p>Before the AI processes your PDF, getbased runs automatic checks:</p><ul><li><strong>Model mismatch</strong> — if you&#39;ve changed your AI model since the last import, a warning explains that different models may generate different marker keys. You can continue or switch back</li><li><strong>PII scan</strong> — a notification confirms that personal information will be stripped before sending to the AI</li></ul><p>These checks help prevent data consistency issues and keep you informed about privacy.</p><h2 id="the-import-preview" tabindex="-1">The Import Preview <a class="header-anchor" href="#the-import-preview" aria-label="Permalink to &quot;The Import Preview&quot;">​</a></h2><p>Before anything is saved, getbased shows you exactly what it found:</p><ul><li><strong>Green — Matched</strong>: Markers recognized and mapped to a known biomarker (e.g., glucose, TSH, ferritin)</li><li><strong>Blue — New</strong>: Markers not in the built-in list, auto-created as <a href="./custom-markers.html">custom markers</a> with AI-suggested names and reference ranges</li><li><strong>Yellow — Unmatched</strong>: Results the AI found but could not confidently identify — these are skipped</li></ul><p>Review the preview carefully. You can dismiss the import if something looks wrong and try again.</p><div class="tip custom-block"><p class="custom-block-title">Any language, any format</p><p>getbased handles reports from any country. The AI understands marker names in English, French, German, Spanish, Dutch, and many other languages, and maps them to the correct biomarkers regardless of the name used.</p></div><h2 id="specialty-labs" tabindex="-1">Specialty Labs <a class="header-anchor" href="#specialty-labs" aria-label="Permalink to &quot;Specialty Labs&quot;">​</a></h2><p>getbased automatically detects non-blood tests — OAT, DUTCH, HTMA, amino acids, and more. The AI identifies the test type and routes markers through the specialty pipeline with your lab&#39;s stated reference ranges. See <a href="./specialty-labs.html">Specialty Labs</a> for full details.</p><h2 id="what-gets-extracted" tabindex="-1">What Gets Extracted <a class="header-anchor" href="#what-gets-extracted" aria-label="Permalink to &quot;What Gets Extracted&quot;">​</a></h2><p>getbased tracks 287+ biomarkers across 16 categories:</p><ul><li>Biochemistry (glucose, liver enzymes, kidney markers, electrolytes)</li><li>Hormones (testosterone, estradiol, cortisol, DHEA, insulin, and more)</li><li>Lipids (cholesterol, triglycerides, LDL, HDL, ratios)</li><li>Hematology (CBC, red and white cell indices)</li><li>Thyroid (TSH, T3, T4, antibodies)</li><li>And 11 more categories</li></ul><p>Markers not in the built-in schema are automatically created as custom markers and tracked alongside the built-in ones.</p><h2 id="privacy-during-import" tabindex="-1">Privacy During Import <a class="header-anchor" href="#privacy-during-import" aria-label="Permalink to &quot;Privacy During Import&quot;">​</a></h2><p>Your PDF is processed locally first. Personal information (name, address, date of birth, ID numbers) is stripped out before anything is sent to your AI provider. See <a href="./pii-obfuscation.html">PII Obfuscation</a> for full details on how this works.</p><h2 id="common-questions" tabindex="-1">Common Questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common Questions&quot;">​</a></h2><p><strong>Can I import the same PDF twice?</strong> If you import a report for a date that already has data, the new values are merged with existing ones for that date. Existing values are not overwritten.</p><p><strong>What if results are missing from the preview?</strong> Some PDFs use image-based scans rather than text. The AI can only extract text that pdf.js can read. Try a PDF exported directly from your lab&#39;s portal rather than a scanned photo if possible.</p><p><strong>Can I undo an import?</strong> Not directly after confirming, but you can export your data as JSON before importing (as a backup), or use <strong>Settings → Backup &amp; Restore</strong> to roll back to an automatic snapshot.</p>',28)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
